#include <bits/stdc++.h>
using namespace std;

const int N=35,mod=376544743;

int n,m,p[N];
int ans;

inline int cal(int num){
	int l=num,r=m/num*num;
	return 1ll*(l+r)*(m/num)/2%mod; 
} 

void dfs(int x,int num,int cnt){ 
    if(x>n){
        if(cnt%2)
            ans=(ans+cal(num))%mod;
        else if(cnt) 
            ans=(ans-cal(num))%mod;
        return;
    }
    dfs(x+1,num,cnt);
    if(1ll*num*p[x]<=m)
        dfs(x+1,num*p[x],cnt+1);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    sort(p+1,p+n+1,greater<int>());
    dfs(1,1,0);
    printf("%d",(ans+mod)%mod);
    return 0;
}
